import { useState, useEffect, useContext } from "react"
import AppContext from "../../context"
import { FormSensorConfigEntity, SensorConfigEntity, SensorConfigRealtime } from '../../entities/SensorConfigEntity'
import styles from './SensorConfig.module.css'
import { FiLink } from 'react-icons/fi'
import { PiPlugsConnected } from 'react-icons/pi'
import { TbPlugConnected } from 'react-icons/tb'
import item1 from '../../assets/images/sensor_pressure.png'
import item2 from '../../assets/images/logo-sensor-vibration.png'
import { PopUpPilihEntity } from "../../components/Popup/PopupPilihEntity"
import PopupPilih from "../../components/Popup/PopupPilih"
import Popup from "../../components/Popup/Popup"
import { AlertEntity } from "../../layouts/Alert/AlertEntity"
import { SensorConfigService } from "../../services/sensor_config"

import { RxThickArrowLeft, RxThickArrowRight } from "react-icons/rx"
import { MachineService } from "../../services/machine"
import { MachineEntity } from "../../entities/MachineEntity"

export default function SensorConfig() {
    // ========================================= GLOBAL CONTEXT =========================================  //
    const context = useContext(AppContext)
    const contextAccessToken = context.contextAccessToken
    const contextShowAlertFunc = context.contextShowAlertFunc
    const contextShowLoadingFunc = context.contextShowLoadingFunc
    const stateShowLoading = context.stateShowLoading
    // ========================================= GLOBAL CONTEXT =========================================  //
    const [selectedMachine, setSelectedMachine] = useState<MachineEntity | null>(null)
    const [selectedConfig, setSelectedConfig] = useState<SensorConfigEntity | null>(null)
    const [formConfig, setFormConfig] = useState<FormSensorConfigEntity | null>(null)

    const [showPopupPilih, setShowPopupPilih] = useState(false)
    const [popUpPilihEntity, setPopUpPilihEntity] = useState<PopUpPilihEntity>()
    const [dataRealtime, setDataRealtime] = useState<SensorConfigRealtime[]>([])

    const pageList = ['Vibration', 'Pressure']
    const [currentPageIndex, setCurrentPageIndex] = useState(0)
    const currentPage = pageList[currentPageIndex]

    const handleNextPage = () => {
        if (currentPageIndex < pageList.length - 1) {
            setCurrentPageIndex(prevIndex => prevIndex + 1)
        }
    }

    const handlePrevPage = () => {
        if (currentPageIndex > 0) {
            setCurrentPageIndex(prevIndex => prevIndex - 1)
        }
    }

    const handleSelectMachine = async () => {
        contextShowLoadingFunc(true)
        try {
            const resp = await MachineService.GetAllMachine()
            setPopUpPilihEntity(new PopUpPilihEntity({
                popupTitle: 'Select Machine',
                tableContent: resp,
                onClick: async (row: MachineEntity) => { generateDataConfig(row) },
                onClose: () => { setShowPopupPilih(false) }
            }))
            setShowPopupPilih(true)
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({
                message: error instanceof Error ? error.message : error.toString(),
                level: 3
            }))
        } finally {
            contextShowLoadingFunc(false)
        }
    }

    const generateDataConfig = async (row: MachineEntity) => {
        try {
            const config = await SensorConfigService.GetSensorConfigByMachineID(row.machine_id)
            setSelectedMachine(row)
            setSelectedConfig(config)
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({
                message: error instanceof Error ? error.message : error.toString(),
                level: 3
            }))
        }
    }

    const PopupInputData = (props: {
        label: string
        type_input: "text" | "number"
        value: string | number
        required: boolean
        attribute: keyof FormSensorConfigEntity
        onchange?: (event: React.ChangeEvent<HTMLInputElement>) => void
    }) => {
        const { label, value, required, attribute, onchange, type_input } = props

        const numberInput: (keyof FormSensorConfigEntity)[] = [
            'pressure_max_warn', 'pressure_max_alarm', 'x_warn', 'x_alarm', 'x_acc_warn', 'x_acc_alarm', 'z_warn',
            'pressure_min_warn', 'pressure_min_alarm', 'z_alarm', 'z_acc_warn', 'z_acc_alarm', 'temp_warn', 'temp_alarm',
        ]
        const isNumberField = numberInput.includes(attribute)

        return <>
            <div>{label} {required && <span style={{ color: "red" }}>*</span>}</div>
            <input type={type_input} style={{ marginBottom: "0.5rem", fontSize: "1rem", fontWeight: "bolder" }} value={value}
                onChange={onchange ?? ((event) => {
                    const newValue = isNumberField ? parseInt(event.target.value) : event.target.value

                    setFormConfig((prev) => {
                        return { ...prev, [attribute]: newValue, }
                    })
                })}
            />
        </>
    }

    const handleSaveChange = async () => {
        contextShowLoadingFunc(true)
        try {
            if (!selectedMachine) {
                throw new Error("No machine selected!")
            }
            if (!formConfig) {
                throw new Error("No updated data yet!")
            }

            const resp = await SensorConfigService.AddSensorConfig(selectedMachine.machine_id, formConfig)
            setFormConfig(null)
            generateDataConfig(selectedMachine)

            contextShowAlertFunc(new AlertEntity({ message: resp.message, level: 1 }))
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3 }))
        } finally {
            contextShowLoadingFunc(false)
        }
    }

    const generateDataRealtime = async () => {
        if (selectedMachine == undefined) { return }
        try {
            const resp = await SensorConfigService.GetSensorConfigRealtime(selectedMachine.machine_id)
            setDataRealtime(resp)
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({
                message: error instanceof Error ? error.message : error.toString(),
                level: 3,
            }))
        }
    }

    const statusConnect = () => {
        if (currentPage === 'Pressure') {
            return dataRealtime[0]?.pressure_connect || false
        } else {
            return dataRealtime[0]?.vibration_connect === 128
        }
    }

    useEffect(() => {
        generateDataRealtime()
        if (selectedMachine) {
            const interval = setInterval(generateDataRealtime, 1000)
            return () => {
                clearInterval(interval)
            }
        }
    }, [contextAccessToken, selectedMachine])

    return (
        <div className="container">
            <div className={styles.conWrapper}>
                <div className={styles.conItem}>
                    <div className={styles.conHeader}>
                        Sensor Config
                    </div>
                    <div className={styles.conBody}>
                        <div className={styles.bodyWrapper}>

                            <div className={styles.bodyLeft}>
                                <div className={styles.bodyLeftHeader}>
                                    <div className={styles.headerItem}>
                                        <span className={`${styles.headerDot} ${statusConnect() ? styles.headerConnect : styles.headerDisconnect}`}></span>
                                        {statusConnect() ? 'Connected' : 'Not Connected'}
                                    </div>
                                </div>
                                <div className={styles.bodyLeftBody}>
                                    <div className={styles.bodyLeftBodyCard}>
                                        <div className={styles.deviceImageWrapper}>
                                            <img src={currentPage == 'Pressure' ? item1 : item2} alt="QM30VT2 Sensor" className={styles.deviceImage} />
                                        </div>

                                        <div className={styles.deviceInfo}>
                                            <div className={styles.label}>Device</div>
                                            <input className={styles.input} type="text" readOnly
                                                value={selectedMachine?.machine ?? ""}
                                                onClick={handleSelectMachine}
                                            />

                                            <div className={styles.label}>Detail Information</div>
                                            <div className={styles.infoRow}>
                                                <div className={styles.infoLabel}>
                                                    <div>Link Up</div>
                                                </div>
                                                <div className={styles.infoValue}>
                                                    <div>: {selectedMachine?.link_up ?? "--"}</div>
                                                </div>
                                            </div>
                                            <div className={styles.infoRow}>
                                                <div className={styles.infoLabel}>
                                                    <div>Machine Type</div>
                                                </div>
                                                <div className={styles.infoValue}>
                                                    <div>: {selectedMachine?.machine_type ?? "--"}</div>
                                                </div>
                                            </div>
                                            <div className={styles.infoRow}>
                                                <div className={styles.infoLabel}>
                                                    <div>Gateway Host</div>
                                                </div>
                                                <div className={styles.infoValue}>
                                                    <div>: {selectedMachine?.gateway_host ?? "--"}</div>
                                                </div>
                                            </div>
                                            <div className={styles.infoRow}>
                                                <div className={styles.infoLabel}>
                                                    <div>Gateway Port</div>
                                                </div>
                                                <div className={styles.infoValue}>
                                                    <div>: {selectedMachine?.gateway_port ?? "--"}</div>
                                                </div>
                                            </div>
                                            <div className={styles.infoRow}>
                                                <div className={styles.infoLabel}>
                                                    <div>{currentPage == 'Pressure' ? 'Pressure Slave Id' : currentPage == 'Vibration' ? 'Vibration Slave Id' : 'Slave Id'}</div>
                                                </div>
                                                <div className={styles.infoValue}>
                                                    <div>: {currentPage == 'Pressure' ? selectedMachine?.pressure_slave_id : selectedMachine?.vibration_slave_id ?? '--'}</div>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                                <div className={styles.bodyLeftFooter}>
                                    <button className={styles.bodyLeftFooterButton}>
                                        {statusConnect() ? <PiPlugsConnected size={20} /> : <TbPlugConnected size={20} />}
                                        {statusConnect() ? "Disconnect" : "Connect"}
                                    </button>
                                </div>
                            </div>

                            <div className={styles.bodyRight}>
                                <div className={styles.bodyRightForm}>
                                    {selectedMachine
                                        ? currentPage === 'Vibration'
                                            ? <>
                                                <div className={styles.formLeft}>
                                                    <div className={styles.label}> X </div>
                                                    <input className={styles.inputedit} type="text" readOnly
                                                        value={dataRealtime[0]?.x ?? ""}
                                                    />
                                                    {PopupInputData({
                                                        label: "X Warn", value: formConfig?.x_warn ?? selectedConfig?.x_warn ?? '', type_input: 'number',
                                                        attribute: "x_warn", required: true
                                                    })}
                                                    {PopupInputData({
                                                        label: "X Alarm", value: formConfig?.x_alarm ?? selectedConfig?.x_alarm ?? '', type_input: 'number',
                                                        attribute: "x_alarm", required: true
                                                    })}
                                                    <div className={styles.label}> X Acc</div>
                                                    <input className={styles.inputedit} type="text" readOnly
                                                        value={dataRealtime[0]?.x_acc ?? ""}
                                                    />
                                                    {PopupInputData({
                                                        label: "X Acc Warn", value: formConfig?.x_acc_warn ?? selectedConfig?.x_acc_warn ?? '', type_input: 'number',
                                                        attribute: "x_acc_warn", required: true
                                                    })}
                                                </div>
                                                <div className={styles.formMid}>
                                                    {PopupInputData({
                                                        label: "X Acc Alarm", value: formConfig?.x_acc_alarm ?? selectedConfig?.x_acc_alarm ?? '', type_input: 'number',
                                                        attribute: "x_acc_alarm", required: true
                                                    })}
                                                    <div className={styles.label}> Z </div>
                                                    <input className={styles.inputedit} type="text" readOnly
                                                        value={dataRealtime[0]?.z ?? ""}
                                                    />
                                                    {PopupInputData({
                                                        label: "Z Warn", value: formConfig?.z_warn ?? selectedConfig?.z_warn ?? '', type_input: 'number',
                                                        attribute: "z_warn", required: true
                                                    })}
                                                    {PopupInputData({
                                                        label: "Z Alarm", value: formConfig?.z_alarm ?? selectedConfig?.z_alarm ?? '', type_input: 'number',
                                                        attribute: "z_alarm", required: true
                                                    })}
                                                    <div className={styles.label}> Z Acc</div>
                                                    <input className={styles.inputedit} type="text" readOnly
                                                        value={dataRealtime[0]?.z_acc ?? ""}
                                                    />
                                                </div>
                                                <div className={styles.formRight}>
                                                    {PopupInputData({
                                                        label: "Z Acc Warn", value: formConfig?.z_acc_warn ?? selectedConfig?.z_acc_warn ?? '', type_input: 'number',
                                                        attribute: "z_acc_warn", required: true
                                                    })}
                                                    {PopupInputData({
                                                        label: "Z Acc Alarm", value: formConfig?.z_acc_alarm ?? selectedConfig?.z_acc_alarm ?? '', type_input: 'number',
                                                        attribute: "z_acc_alarm", required: true
                                                    })}
                                                    <div className={styles.label}> Temp </div>
                                                    <input className={styles.inputedit} type="text" readOnly
                                                        value={dataRealtime[0]?.temp ?? ""}
                                                    />
                                                    {PopupInputData({
                                                        label: "Temp Warn", value: formConfig?.temp_warn ?? selectedConfig?.temp_warn ?? '', type_input: 'number',
                                                        attribute: "temp_warn", required: true
                                                    })}
                                                    {PopupInputData({
                                                        label: "Temp Alarm", value: formConfig?.temp_alarm ?? selectedConfig?.temp_alarm ?? '', type_input: 'number',
                                                        attribute: "temp_alarm", required: true
                                                    })}
                                                </div>
                                            </>
                                            : <>
                                                <div className={styles.formLeft}>
                                                    <div className={styles.label}> Pressure Data </div>
                                                    <input className={styles.inputedit} type="text" readOnly
                                                        value={dataRealtime[0]?.pressure ?? ""}
                                                    />
                                                    {PopupInputData({
                                                        label: "Pressure Max Warn", value: formConfig?.pressure_max_warn ?? selectedConfig?.pressure_max_warn ?? '', type_input: 'number',
                                                        attribute: "pressure_max_warn", required: true
                                                    })}
                                                    {PopupInputData({
                                                        label: "Pressure Max Alarm", value: formConfig?.pressure_max_alarm ?? selectedConfig?.pressure_max_alarm ?? '', type_input: 'number',
                                                        attribute: "pressure_max_alarm", required: true
                                                    })}
                                                </div>
                                                <div className={styles.formRight}>
                                                    {PopupInputData({
                                                        label: "Pressure Min Warn", value: formConfig?.pressure_min_warn ?? selectedConfig?.pressure_min_warn ?? '', type_input: 'number',
                                                        attribute: "pressure_min_warn", required: true
                                                    })}
                                                    {PopupInputData({
                                                        label: "Pressure Min Alarm", value: formConfig?.pressure_min_alarm ?? selectedConfig?.pressure_min_alarm ?? '', type_input: 'number',
                                                        attribute: "pressure_min_alarm", required: true
                                                    })}
                                                </div>
                                            </>
                                        : <></>
                                    }
                                </div>
                                <div className={styles.bodyRightButton}>
                                    <button
                                        className={`${styles.pageButton} ${currentPageIndex === 0 ? styles.active : ''}`}
                                        onClick={handlePrevPage}
                                    >
                                        <RxThickArrowLeft />
                                        <span className={styles.tooltipText}>Previous</span>
                                    </button>
                                    <div className={styles.pageIndicatorWrapper}>
                                        <span className={styles.pageIndicator}>
                                            {currentPage}
                                        </span>
                                    </div>
                                    <button
                                        className={`${styles.pageButton} ${currentPageIndex === pageList.length - 1 ? styles.active : ''}`}
                                        onClick={handleNextPage}
                                    >
                                        <RxThickArrowRight />
                                        <span className={styles.tooltipText}>Next</span>
                                    </button>
                                </div>
                                <div className={styles.bodyRightStatus}>
                                    <div className={styles.bodyRightStatusLeft}>
                                        <div className={styles.paramItem}>
                                            <span className={`${styles.statusDot} ${styles.statusRead}`}></span>
                                            Editable Parameters
                                        </div>
                                        <div className={styles.paramItem}>
                                            <span className={`${styles.statusDot} ${styles.statusEditable}`}></span>
                                            Read-Only Parameters
                                        </div>
                                    </div>
                                    <div className={styles.bodyRightStatusRight}>
                                        <button className={styles.saveButton} onClick={handleSaveChange}>
                                            Save Change
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>

            </div>

            {popUpPilihEntity != null
                ? <PopupPilih
                    showPopup={showPopupPilih}
                    setShowPopup={setShowPopupPilih}
                    popUpPilihEntity={popUpPilihEntity}
                />
                : <></>}
        </div>
    )
}