import { BASE_URL } from "../constants"
import { SensorConfigEntity, FormSensorConfigEntity, SensorConfigRealtime } from "../entities/SensorConfigEntity"
import FetchUtils from "../utils/fetch"

class SensorConfigService {
    static async GetSensorConfigByMachineID(machine_id: number): Promise<SensorConfigEntity> {
        let resp = await FetchUtils.fetchAuth(`${BASE_URL}/api/v1/machine/config?machine_id=${machine_id}`)

        if (resp.status !== 200) {
            throw new Error(resp.message)
        }

        const data: SensorConfigEntity = {
            machine_id: resp.data.machine_id,
            pressure_max_warn: resp.data.pressure_max_warn,
            pressure_max_alarm: resp.data.pressure_max_alarm,
            pressure_min_warn: resp.data.pressure_min_warn,
            pressure_min_alarm: resp.data.pressure_min_alarm,
            x_warn: resp.data.x_warn,
            x_alarm: resp.data.x_alarm,
            x_acc_warn: resp.data.x_acc_warn,
            x_acc_alarm: resp.data.x_acc_alarm,
            z_warn: resp.data.z_warn,
            z_alarm: resp.data.z_alarm,
            z_acc_warn: resp.data.z_acc_warn,
            z_acc_alarm: resp.data.z_acc_alarm,
            temp_warn: resp.data.temp_warn,
            temp_alarm: resp.data.temp_alarm,
        }

        return data
    }

    static async AddSensorConfig(machine_id: number, fields: FormSensorConfigEntity): Promise<{ message: string }> {
        let resp = await FetchUtils.fetchAuth(`${BASE_URL}/api/v1/machine/config`, {
            method: 'POST',
            body: JSON.stringify({ machine_id, fields }),
            headers: { "Content-Type": "application/json" }
        })

        if (resp.status !== 200) {
            throw new Error(resp.message)
        }

        return resp
    }

    static async GetSensorConfigRealtime(machine_id: number,): Promise<SensorConfigRealtime[]> {
        const resp = await FetchUtils.fetchAuth(`${BASE_URL}/api/v1/machine/config/realtime?machine_id=${encodeURIComponent(machine_id)}`)

        if (resp.status !== 200) {
            throw new Error("Failed to fetch sensor config realtime data.")
        }

        const result: SensorConfigRealtime[] = []
        for (let i = 0; i < resp.data.length; i++) {
            const row = resp.data[i]

            result.push({
                pressure: row.pressure_last_data.pressure,
                pressure_connect: row.pressure_last_data.connect,
                x: row.vibration_last_data.x,
                x_acc: row.vibration_last_data.x_acc,
                z: row.vibration_last_data.z,
                z_acc: row.vibration_last_data.z_acc,
                temp: row.vibration_last_data.temp,
                vibration_connect: row.vibration_last_data.connect
            })
        }

        return result
    }
}

export { SensorConfigService }